import { useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { Dropdown } from './Dropdown';
import { DropdownMenu } from './DropdownMenu';
import { DropdownItem } from './DropdownItem';
import { Button } from '../Button';
import { Space } from '../Space';
import { Text } from '../Text';
import { EditGlyph, DeleteGlyph, PlusGlyph } from '../../stories/icons';

const menu = (
  <DropdownMenu>
    <DropdownItem command="new" icon={PlusGlyph}>
      New item
    </DropdownItem>
    <DropdownItem command="edit" icon={EditGlyph}>
      Edit
    </DropdownItem>
    <DropdownItem command="duplicate">Duplicate</DropdownItem>
    <DropdownItem command="delete" icon={DeleteGlyph} divided>
      Delete
    </DropdownItem>
  </DropdownMenu>
);

const meta = {
  title: 'Components/Dropdown',
  component: Dropdown,
  tags: ['autodocs'],
  argTypes: {
    trigger: { control: 'inline-radio', options: ['hover', 'click'] },
    placement: { control: 'text' },
    disabled: { control: 'boolean' },
    hideOnClick: { control: 'boolean' },
    size: { control: 'inline-radio', options: ['large', 'default', 'small'] },
    menu: { control: false },
    children: { control: false },
  },
  args: {
    // Required props; each story supplies its own via `render`.
    menu,
    children: <Button type="primary">Actions</Button>,
  },
} satisfies Meta<typeof Dropdown>;

export default meta;
type Story = StoryObj<typeof meta>;

export const HoverTrigger: Story = {
  name: 'Hover trigger',
  render: () => {
    const [last, setLast] = useState('—');
    return (
      <Space align="center">
        <Dropdown menu={menu} onCommand={(c) => setLast(String(c))}>
          <Button type="primary">Actions</Button>
        </Dropdown>
        <Text type="info" size="small">
          last command: {last}
        </Text>
      </Space>
    );
  },
};

export const ClickTrigger: Story = {
  name: 'Click trigger',
  render: () => {
    const [last, setLast] = useState('—');
    return (
      <Space align="center">
        <Dropdown trigger="click" menu={menu} onCommand={(c) => setLast(String(c))}>
          <Button>Open on click</Button>
        </Dropdown>
        <Text type="info" size="small">
          last command: {last}
        </Text>
      </Space>
    );
  },
};

import {
  cloneElement,
  createContext,
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  isValidElement,
  type ReactElement,
  type ReactNode,
  useMemo,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useSize } from '../../config-provider';
import { type Placement, Popper } from '../Overlay';

export type DropdownTrigger = 'hover' | 'click';

export interface DropdownContextValue {
  /** Fire the parent `onCommand` handler with an item's command payload. */
  onCommand: (command: unknown) => void;
  /** Close the dropdown menu. */
  close: () => void;
  /** Resolved component size, shared with menu items. */
  size: ComponentSize;
  /** Close the menu after an item is clicked. */
  hideOnClick: boolean;
}

export const DropdownContext = createContext<DropdownContextValue | null>(null);

export interface DropdownProps extends Omit<HTMLAttributes<HTMLDivElement>, 'children'> {
  /** Trigger element (e.g. a Button) that toggles the menu. */
  children: ReactElement;
  /** Menu content, usually a `DropdownMenu` of `DropdownItem`. */
  menu: ReactNode;
  /** How the menu opens. */
  trigger?: DropdownTrigger;
  /** Placement of the menu relative to the trigger. */
  placement?: Placement;
  /** Disable the dropdown entirely. */
  disabled?: boolean;
  /** Close the menu when an item is clicked. */
  hideOnClick?: boolean;
  /** Size, applied to descendant items. Falls back to the nearest ConfigProvider. */
  size?: ComponentSize;
  /** Fired with the clicked item's `command`. */
  onCommand?: (command: unknown) => void;
  /** Fired when the menu opens or closes. */
  onVisibleChange?: (visible: boolean) => void;
}

export const Dropdown = forwardRef<HTMLDivElement, DropdownProps>(function Dropdown(props, ref) {
  const {
    children,
    menu,
    trigger = 'hover',
    placement = 'bottom-end',
    disabled = false,
    hideOnClick = true,
    size: sizeProp,
    onCommand,
    onVisibleChange,
    className,
    style,
    ...rest
  } = props;

  const ns = useNamespace('dropdown');
  const size = useSize(sizeProp);

  const [open, setOpen] = useState(false);

  const handleOpenChange = (next: boolean) => {
    setOpen(next);
    onVisibleChange?.(next);
  };

  const context = useMemo<DropdownContextValue>(
    () => ({
      onCommand: (command) => onCommand?.(command),
      close: () => {
        setOpen(false);
        onVisibleChange?.(false);
      },
      size,
      hideOnClick,
    }),
    [onCommand, onVisibleChange, size, hideOnClick],
  );

  if (!isValidElement(children)) {
    return <>{children}</>;
  }

  const reference = cloneElement(children, {
    className: cls(ns.e('trigger'), (children.props as { className?: string }).className),
  } as Record<string, unknown>);

  return (
    <DropdownContext.Provider value={context}>
      <div
        ref={ref}
        className={cls(ns.b(), className)}
        style={style as CSSProperties}
        {...rest}
      >
        <Popper
          reference={reference}
          trigger={trigger}
          placement={placement}
          offset={6}
          role="dialog"
          popperClass={ns.e('popper')}
          disabled={disabled}
          open={open}
          onOpenChange={handleOpenChange}
        >
          {menu}
        </Popper>
      </div>
    </DropdownContext.Provider>
  );
});

import type { Meta, StoryObj } from '@storybook/react-vite';
import { DropdownItem } from './DropdownItem';
import { DropdownMenu } from './DropdownMenu';
import { Dropdown } from './Dropdown';
import { Button } from '../Button';
import { EditGlyph, DeleteGlyph } from '../../stories/icons';

const meta = {
  title: 'Components/DropdownItem',
  component: DropdownItem,
  tags: ['autodocs'],
  argTypes: {
    disabled: { control: 'boolean' },
    divided: { control: 'boolean' },
    icon: { control: false },
  },
} satisfies Meta<typeof DropdownItem>;

export default meta;
type Story = StoryObj<typeof meta>;

export const InsideDropdown: Story = {
  name: 'Inside a Dropdown',
  render: () => (
    <Dropdown
      trigger="click"
      menu={
        <DropdownMenu>
          <DropdownItem command="edit" icon={EditGlyph}>
            Edit
          </DropdownItem>
          <DropdownItem command="disabled" disabled>
            Disabled
          </DropdownItem>
          <DropdownItem command="delete" icon={DeleteGlyph} divided>
            Delete
          </DropdownItem>
        </DropdownMenu>
      }
    >
      <Button type="primary">Open menu</Button>
    </Dropdown>
  ),
};

import {
  type FocusEvent,
  forwardRef,
  type HTMLAttributes,
  type KeyboardEvent,
  type MouseEvent,
  type ReactNode,
  useContext,
  useId,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { DropdownContext } from './Dropdown';
import { DropdownMenuContext } from './DropdownMenu';

export interface DropdownItemProps extends Omit<HTMLAttributes<HTMLLIElement>, 'onClick'> {
  /** Payload passed to the parent `onCommand` handler when clicked. */
  command?: unknown;
  /** Disable the item. */
  disabled?: boolean;
  /** Render a separator above the item. */
  divided?: boolean;
  /** Leading icon. */
  icon?: ReactNode;
  children?: ReactNode;
}

export const DropdownItem = forwardRef<HTMLLIElement, DropdownItemProps>(
  function DropdownItem(props, ref) {
    const {
      command,
      disabled = false,
      divided = false,
      icon,
      className,
      children,
      id: idProp,
      onFocus,
      onKeyDown,
      ...rest
    } = props;

    const ns = useNamespace('dropdown-menu');
    const context = useContext(DropdownContext);
    const menu = useContext(DropdownMenuContext);

    const generatedId = useId();
    const id = idProp ?? generatedId;

    /** Shared activation path for both pointer and keyboard. */
    const activate = () => {
      if (disabled) return;
      context?.onCommand(command);
      if (context?.hideOnClick) {
        context.close();
      }
    };

    const handleClick = (event: MouseEvent<HTMLLIElement>) => {
      if (disabled) {
        event.preventDefault();
        return;
      }
      activate();
    };

    const handleKeyDown = (event: KeyboardEvent<HTMLLIElement>) => {
      if (!disabled && (event.key === 'Enter' || event.key === ' ')) {
        // Space would otherwise scroll the page.
        event.preventDefault();
        activate();
      }
      onKeyDown?.(event);
    };

    const handleFocus = (event: FocusEvent<HTMLLIElement>) => {
      if (!disabled) {
        menu?.setActiveId(id);
      }
      onFocus?.(event);
    };

    const classes = cls(
      ns.e('item'),
      context && context.size !== 'default' && ns.m(context.size),
      ns.is('disabled', disabled),
      ns.is('divided', divided),
      className,
    );

    // Roving tabindex: the active item is the single tab stop. Before any item
    // has been focused, the first enabled item is reachable by Tab.
    const isActive = menu ? menu.activeId === id : true;
    const tabIndex = disabled ? -1 : isActive ? 0 : -1;

    return (
      <li
        ref={ref}
        id={id}
        className={classes}
        role="menuitem"
        tabIndex={tabIndex}
        aria-disabled={disabled || undefined}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        onFocus={handleFocus}
        {...rest}
      >
        {icon && <span className={ns.e('icon')}>{icon}</span>}
        {children}
      </li>
    );
  },
);

import type { Meta, StoryObj } from '@storybook/react-vite';
import { DropdownMenu } from './DropdownMenu';
import { DropdownItem } from './DropdownItem';
import { Dropdown } from './Dropdown';
import { Button } from '../Button';

const meta = {
  title: 'Components/DropdownMenu',
  component: DropdownMenu,
  tags: ['autodocs'],
} satisfies Meta<typeof DropdownMenu>;

export default meta;
type Story = StoryObj<typeof meta>;

export const InsideDropdown: Story = {
  name: 'Inside a Dropdown',
  render: () => (
    <Dropdown
      trigger="click"
      menu={
        <DropdownMenu>
          <DropdownItem command="a">First</DropdownItem>
          <DropdownItem command="b">Second</DropdownItem>
          <DropdownItem command="c">Third</DropdownItem>
        </DropdownMenu>
      }
    >
      <Button type="primary">Open menu</Button>
    </Dropdown>
  ),
