import {
  createContext,
  forwardRef,
  type HTMLAttributes,
  type KeyboardEvent,
  type ReactNode,
  useCallback,
  useLayoutEffect,
  useRef,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';

export interface DropdownMenuContextValue {
  /** Stable id of the item that currently holds the roving tab stop. */
  activeId: string | null;
  /** Register an item as the active (focusable) one, e.g. on focus/hover. */
  setActiveId: (id: string | null) => void;
}

/**
 * Scoped to a single `DropdownMenu` so each menu manages its own roving focus.
 */
export const DropdownMenuContext = createContext<DropdownMenuContextValue | null>(null);

export interface DropdownMenuProps extends HTMLAttributes<HTMLUListElement> {
  children?: ReactNode;
}

/** Enabled, focusable menu items in DOM order. */
function getItems(menu: HTMLUListElement | null): HTMLElement[] {
  if (!menu) return [];
  return Array.from(
    menu.querySelectorAll<HTMLElement>('[role="menuitem"]:not([aria-disabled="true"])'),
  );
}

export const DropdownMenu = forwardRef<HTMLUListElement, DropdownMenuProps>(
  function DropdownMenu(props, ref) {
    const { className, children, onKeyDown, ...rest } = props;
    const ns = useNamespace('dropdown-menu');

    const menuRef = useRef<HTMLUListElement | null>(null);
    const [activeId, setActiveId] = useState<string | null>(null);

    // Seed the roving tab stop on the first enabled item so the menu has
    // exactly one tab stop before the user moves focus.
    useLayoutEffect(() => {
      if (activeId === null) {
        const first = getItems(menuRef.current)[0];
        if (first?.id) setActiveId(first.id);
      }
    });

    const setRefs = useCallback(
      (node: HTMLUListElement | null) => {
        menuRef.current = node;
        if (typeof ref === 'function') ref(node);
        else if (ref) ref.current = node;
      },
      [ref],
    );

    const focusItem = useCallback((item: HTMLElement | undefined) => {
      if (item) {
        item.focus();
        setActiveId(item.id || null);
      }
    }, []);

    const handleKeyDown = useCallback(
      (event: KeyboardEvent<HTMLUListElement>) => {
        const items = getItems(menuRef.current);
        if (items.length > 0) {
          const current = document.activeElement as HTMLElement | null;
          const index = current ? items.indexOf(current) : -1;

          switch (event.key) {
            case 'ArrowDown': {
              event.preventDefault();
              focusItem(items[index < 0 ? 0 : (index + 1) % items.length]);
              break;
            }
            case 'ArrowUp': {
              event.preventDefault();
              focusItem(items[index <= 0 ? items.length - 1 : index - 1]);
              break;
            }
            case 'Home': {
              event.preventDefault();
              focusItem(items[0]);
              break;
            }
            case 'End': {
              event.preventDefault();
              focusItem(items[items.length - 1]);
              break;
            }
            default:
              break;
          }
        }

        onKeyDown?.(event);
      },
      [focusItem, onKeyDown],
    );

    return (
      <DropdownMenuContext.Provider value={{ activeId, setActiveId }}>
        <ul
          ref={setRefs}
          className={cls(ns.b(), className)}
          role="menu"
          onKeyDown={handleKeyDown}
          {...rest}
        >
          {children}
        </ul>
      </DropdownMenuContext.Provider>
    );
  },
);

.ec-dropdown {
  display: inline-block;
  box-sizing: border-box;
}

.ec-dropdown__trigger {
  outline: none;
}

.ec-dropdown__popper {
  padding: 5px 0;
}

.ec-dropdown-menu {
  box-sizing: border-box;
  list-style: none;
  margin: 0;
  padding: 0;
}

.ec-dropdown-menu__item {
  --ec-dropdown-menu-item-color: var(--ec-text-color-regular);
  --ec-dropdown-menu-item-hover-color: var(--ec-color-primary);
  --ec-dropdown-menu-item-hover-bg-color: var(--ec-fill-color-light);
  --ec-dropdown-menu-item-disabled-color: var(--ec-disabled-text-color);
  --ec-dropdown-menu-item-divider-color: var(--ec-border-color-lighter);
  --ec-dropdown-menu-item-font-size: var(--ec-font-size-base);
  --ec-dropdown-menu-item-padding-vertical: 5px;
  --ec-dropdown-menu-item-padding-horizontal: 16px;

  display: flex;
  align-items: center;
  gap: 8px;
  box-sizing: border-box;
  white-space: nowrap;
  padding: var(--ec-dropdown-menu-item-padding-vertical)
    var(--ec-dropdown-menu-item-padding-horizontal);
  margin: 0;
  font-size: var(--ec-dropdown-menu-item-font-size);
  line-height: 22px;
  color: var(--ec-dropdown-menu-item-color);
  cursor: pointer;
  outline: none;
  transition: var(--ec-transition-all);
}

/* ---- Sizes ---- */
.ec-dropdown-menu__item.ec-dropdown-menu--large {
  --ec-dropdown-menu-item-font-size: var(--ec-font-size-medium);
  --ec-dropdown-menu-item-padding-vertical: 7px;
  --ec-dropdown-menu-item-padding-horizontal: 20px;
}

.ec-dropdown-menu__item.ec-dropdown-menu--small {
  --ec-dropdown-menu-item-font-size: var(--ec-font-size-extra-small);
  --ec-dropdown-menu-item-padding-vertical: 3px;
  --ec-dropdown-menu-item-padding-horizontal: 12px;
}

.ec-dropdown-menu__item:hover,
.ec-dropdown-menu__item:focus-visible {
  color: var(--ec-dropdown-menu-item-hover-color);
  background-color: var(--ec-dropdown-menu-item-hover-bg-color);
}

.ec-dropdown-menu__item.is-disabled {
  color: var(--ec-dropdown-menu-item-disabled-color);
  cursor: not-allowed;
}

.ec-dropdown-menu__item.is-disabled:hover,
.ec-dropdown-menu__item.is-disabled:focus-visible {
  color: var(--ec-dropdown-menu-item-disabled-color);
  background-color: transparent;
}

.ec-dropdown-menu__item.is-divided {
  margin-top: 6px;
  border-top: 1px solid var(--ec-dropdown-menu-item-divider-color);
  padding-top: 6px;
}

.ec-dropdown-menu__icon {
  display: inline-flex;
  align-items: center;
}

export * from './Dropdown';
export * from './DropdownMenu';
export * from './DropdownItem';
